let output = `
<h2>🤖 Daily AI</h2>
<hr>
`;

items.forEach((item, index) => {
    const title = item.json.title || "No title";
    const url = item.json.link || item.json.url || "No URL";
    const date = item.json.pubDate || item.json.date || item.json.publishedAt || "";

    let formattedDate = "";
    if (date) {
        const d = new Date(date);
        formattedDate = d.toLocaleDateString();
    }

    output += `
    <p>
        <b>${index + 1}. ${title}</b> ${formattedDate ? `(${formattedDate})` : ""}<br>
        <a href="${url}">${url}</a>
    </p>
    `;
});

return [
    {
        json: {
            message: output
        }
    }
];

const now = new Date();
const threeDaysAgo = new Date();
threeDaysAgo.setDate(now.getDate() - 3);

// Step 1: Filter last 3 days
let recentItems = items.filter(item => {
    const dateValue = item.json.pubDate || item.json.date || item.json.publishedAt;
    if (!dateValue) return false;

    const pubDate = new Date(dateValue);
    return pubDate >= threeDaysAgo;
});

// Step 2: Sort by latest date (descending)
recentItems.sort((a, b) => {
    const dateA = new Date(a.json.pubDate || a.json.date || a.json.publishedAt);
    const dateB = new Date(b.json.pubDate || b.json.date || b.json.publishedAt);
    return dateB - dateA; // newest first
});

// Step 3: Take top 5
recentItems = recentItems.slice(0, 20);

// Step 4: Fallback if empty
if (recentItems.length === 0) {
    return items.slice(0, 1);
}

return recentItems;
